def _merge_unique(values: list[str], extras: list[str], limit: int = 6) -> list[str]:
    seen: set[str] = set()
    merged: list[str] = []
    for value in [*values, *extras]:
        item = str(value).strip(" -\n\t")
        if not item:
            continue
        key = item.lower()
        if key in seen:
            continue
        seen.add(key)
        merged.append(item)
        if len(merged) >= limit:
            break
    return merged


def _deep_copy_json(value: object) -> object:
    return json.loads(json.dumps(value))


def _strip_greeting_lead(text: object) -> str:
    value = str(text or "").strip()
    if not value:
        return ""
    return re.sub(r"^\s*Good\s+(morning|afternoon|evening)\s*,?\s+[^.?!]+[.?!-:]\s*", "", value, count=1, flags=re.IGNORECASE).strip()


def _default_trust_owner_principal(config: AppConfig, household: HouseholdProfile) -> str:
    configured = str(getattr(config, "default_trust_owner_principal", "") or "").strip().lower()
    if configured:
        return configured
    adults = [
        user.user_id.strip().lower()
        for user in household.users.values()
        if user.user_id.strip() and str(user.permissions or "").strip().lower() == "adult"
    ]
    if adults:
        return adults[0]
    for user in household.users.values():
        candidate = user.user_id.strip().lower()
        if candidate:
            return candidate
    return "primary"


def _access_method_for_host(host: str) -> tuple[str, str]:
    normalized = str(host or "").strip().lower()
    if not normalized:
        return "unknown", "Unknown path"
    hostname = normalized.split(":", 1)[0]
    if hostname.endswith(".ts.net"):
        return "tailscale", "Tailscale"
    if hostname in {"127.0.0.1", "localhost"}:
        return "local", "Local host"
    if hostname.startswith("192.168.") or hostname.startswith("10.") or hostname.startswith("172.16.") or hostname.startswith("172.17.") or hostname.startswith("172.18.") or hostname.startswith("172.19.") or hostname.startswith("172.2") or hostname.startswith("172.30.") or hostname.startswith("172.31."):
        return "lan", "Local network"
    return "direct", "Direct host"


