    def google_disconnect_account(self, account_id: str) -> dict:
        account = self.account_registry.get(account_id)
        if not account:
            return {"ok": False, "message": "Account not found."}
        if account.provider != "google":
            return {"ok": False, "message": f"{account.provider.title()} disconnect is not wired yet."}
        result = self.google_workspace.disconnect(account)
        updated = self.account_registry.update_status(account_id, "planned", "Disconnected from Google.")
        result["account"] = (updated or account).to_dict()
        self._invalidate_snapshot_cache()
        return result

    def disconnect_account(self, account_id: str) -> dict:
        account = self.account_registry.get(account_id)
        if not account:
            return {"ok": False, "message": "Account not found."}
        if account.provider == "google":
            result = self.google_workspace.disconnect(account)
            updated = self.account_registry.update_status(account_id, "planned", "Disconnected from Google.")
            result["account"] = (updated or account).to_dict()
            self._invalidate_snapshot_cache()
            return result
        if account.provider == "outlook":
            result = self.microsoft_graph.disconnect(account)
            updated = self.account_registry.update_status(account_id, "planned", "Disconnected from Microsoft Graph.")
            result["account"] = (updated or account).to_dict()
            self._invalidate_snapshot_cache()
            return result
        return {"ok": False, "message": f"{account.provider.title()} disconnect is not wired yet."}

    def list_personal_accounts(self) -> list[dict]:
        return [item.to_dict() for item in self.account_registry.list_accounts()]

    def account_registry_snapshot(self) -> dict:
        snapshot = self.account_registry.describe()
        accounts = []
        for item in snapshot["accounts"]:
            enriched = dict(item)
            if enriched.get("provider") == "google":
                enriched["connection"] = self.google_account_snapshot(enriched["account_id"])["status"]
            elif enriched.get("provider") == "outlook":
                enriched["connection"] = self.microsoft_account_snapshot(enriched["account_id"])["status"]
            accounts.append(enriched)
        snapshot["accounts"] = accounts
        return snapshot

    def save_personal_account(self, payload: dict) -> dict:
        account = self.account_registry.save_account(payload)
        self._invalidate_snapshot_cache()
        return {
            "message": f"Saved account '{account.label}'.",
            "account": account.to_dict(),
            "registry": self.account_registry_snapshot(),
        }

    def update_personal_account(self, account_id: str, payload: dict) -> dict:
        current = self.account_registry.get(account_id)
        if not current:
            raise KeyError(account_id)
        merged = current.to_dict()
        for field in ("label", "login_hint", "status", "notes", "service_scope"):
            if field in payload:
                merged[field] = payload.get(field)
        account = self.account_registry.save_account(merged)
        self._invalidate_snapshot_cache()
        return {
            "message": f"Updated account '{account.label}'.",
            "account": account.to_dict(),
            "registry": self.account_registry_snapshot(),
        }

    def google_account_snapshot(self, account_id: str) -> dict:
        account = self.account_registry.get(account_id)
        if not account:
            return {"account_id": account_id, "status": self.google_workspace.status().to_dict(), "emails": [], "calendar_events": []}
        summary = self.google_workspace.summary(account)
        profile_email = str(summary.get("profile_email", "")).strip()
        if profile_email and account.login_hint != profile_email:
            updated = self.account_registry.update_login_hint(account.account_id, profile_email)
            if updated:
                account = updated
        summary["account"] = account.to_dict()
        return summary

    def microsoft_account_snapshot(self, account_id: str) -> dict:
        account = self.account_registry.get(account_id)
        if not account:
            return {"account_id": account_id, "status": self.microsoft_graph.status().to_dict(), "emails": [], "calendar_events": []}
        summary = self.microsoft_graph.summary(account)
        profile_email = str(summary.get("profile_email", "")).strip()
        if profile_email and account.login_hint != profile_email:
            updated = self.account_registry.update_login_hint(account.account_id, profile_email)
            if updated:
                account = updated
        summary["account"] = account.to_dict()
        return summary

    def _resolve_google_mailbox_account(self, mailbox_id: str, owner_principal: str = "") -> PersonalAccount | None:
        mailbox_key = str(mailbox_id or "").strip()
        owner_key = str(owner_principal or "").strip().lower()
        if mailbox_key:
            direct = self.account_registry.get(mailbox_key)
            if direct and direct.provider == "google" and direct.service_scope in {"mail", "mail_calendar"}:
                return direct

        accounts = self.account_registry.list_accounts()
        if mailbox_key:
            mailbox_lower = mailbox_key.lower()
            for account in accounts:
                if account.provider != "google" or account.service_scope not in {"mail", "mail_calendar"}:
                    continue
                aliases = {
                    account.account_id.lower(),
                    account.label.lower(),
                    account.login_hint.lower(),
                }
                if mailbox_lower in aliases:
                    return account

        preferred_aliases = {"gmail_primary", "google_primary", "primary", "default"}
        if mailbox_key.lower() in preferred_aliases or not mailbox_key:
            for account in accounts:
                if account.provider != "google" or account.service_scope not in {"mail", "mail_calendar"}:
                    continue
                if owner_key and account.owner_user_id != owner_key:
                    continue
                if account.status == "connected":
                    return account
            bridge_default = str(self.google_workspace.bridge_status().get("default_account_id", "")).strip()
            if bridge_default:
                fallback = self.account_registry.get(bridge_default)
                if fallback and fallback.provider == "google" and fallback.service_scope in {"mail", "mail_calendar"}:
                    return fallback
        return None

    @staticmethod
    def _gmail_reply_subject(subject: str, intent_type: str) -> str:
        cleaned = str(subject or "").strip() or "Email"
        if str(intent_type or "").strip().lower() == "reply" and not cleaned.lower().startswith("re:"):
            return f"Re: {cleaned}"
        return cleaned

    def merged_calendar_events(self, limit: int = 20) -> list[dict]:
        events: list[dict] = []
        google = self.google_workspace_summary()
        for entry in google.get("accounts", []):
            account = entry.get("account", {})
            label = account.get("owner_display_name") or account.get("label") or "Google Calendar"
            for item in entry.get("calendar_events", []):
                events.append(
                    {
                        **item,
                        "source": "google",
                        "source_label": label,
                    }
                )
        family = self.family_calendar_summary()
        family_label = family.get("calendar", {}).get("label", "Family Shared Calendar")
        for item in family.get("events", []):
            events.append(
                {
                    **item,
                    "source": family.get("calendar", {}).get("source", "family"),
                    "source_label": family_label,
                }
            )
        events.sort(key=lambda item: str(item.get("start", "")))
        return events[:limit]

    def merged_calendar_brief(self, limit: int = 5) -> str:
        events = self.merged_calendar_events(limit=limit)
        if not events:
            return "No upcoming calendar pressure in the next 30 days."
        return "; ".join(
            f"{item.get('summary', '(Untitled event)')} on {item.get('start', 'unknown time')}"
            for item in events[:limit]
        )

    def likely_meetings(self, limit: int = 6) -> list[dict]:
        candidates = []
        meeting_keywords = (
            "meeting",
            "call",
            "sync",
            "review",
            "brief",
            "agenda",
            "interview",
            "session",
            "consult",
            "prep",
            "strategy",
            "standup",
            "1:1",
            "check-in",
            "planning",
            "office hours",
            "discovery",
        )
        non_meeting_keywords = (
            "hair",
            "movie",
            "birthday",
            "anniversary",
            "senior sunday",
            "national day",
            "camp",
            "campout",
            "soccer",
            "baseball",
            "basketball",
            "observation",
            "dentist",
            "doctor",
            "appointment",
            "pickup",
            "dropoff",
            "drop-off",
            "travel",
            "flight",
            "church",
            "worship",
            "stag",
            "party",
            "dinner",
            "lunch",
            "breakfast",
            "graduation",
            "concert",
        )
        for item in self.merged_calendar_events(limit=30):
            summary = str(item.get("summary", ""))
            lowered = summary.lower()
            if item.get("all_day"):
                continue
            source = str(item.get("source", "")).lower()
            source_label = str(item.get("source_label", "")).lower()
            if any(token in lowered for token in non_meeting_keywords):
                continue
            has_meeting_signal = any(token in lowered for token in meeting_keywords)
            google_bias = source == "google" and not any(token in source_label for token in ("family", "cozi"))
            if not has_meeting_signal and not google_bias:
                continue
            candidates.append(item)
        return candidates[:limit]

