    def list_promotion_recommendations(self, limit: int = 12) -> list[dict[str, object]]:
        recommendations: list[dict[str, object]] = []

        def _append_recommendation(
            *,
            subject_kind: str,
            subject_id: str,
            target_stage: str,
            actor: str,
            basis: str,
            title: str,
        ) -> None:
            try:
                verdict = self.evaluate_promotion_claim(
                    subject_kind=subject_kind,
                    subject_id=subject_id,
                    target_stage=target_stage,
                    actor=actor,
                    basis=basis,
                    human_consent=False,
                )
            except (KeyError, ValueError):
                return
            decision = str(verdict.get("decision") or "").strip().lower()
            if decision not in {"promote", "pending_consent", "hold", "suspend"}:
                return
            metrics = dict(verdict.get("metrics") or {})
            summary = (
                f"{title} -> {target_stage}: {decision.replace('_', ' ')}. "
                f"Runs {metrics.get('total_reviews', 0)}, success {float(metrics.get('success_rate', 0.0)):.0%}, "
                f"rollbacks {metrics.get('rollback_count', 0)}."
            )
            recommendations.append(
                {
                    "id": str(verdict.get("claim", {}).get("claim_id") or ""),
                    "subject_kind": subject_kind,
                    "subject_id": subject_id,
                    "title": title,
                    "decision": decision,
                    "current_stage": str(verdict.get("current_stage") or ""),
                    "target_stage": str(verdict.get("target_stage") or target_stage),
                    "summary": summary,
                    "reason": str(verdict.get("reason") or ""),
                    "trust_zone": str(verdict.get("trust_zone") or ""),
                    "arena_id": str(verdict.get("arena_id") or ""),
                    "metrics": metrics,
                    "human_consent_required": bool(verdict.get("human_consent_required", False)),
                }
            )

        for zone in self.list_trust_zones():
            if not isinstance(zone, dict):
                continue
            zone_id = str(zone.get("zone_id") or "").strip()
            title = str(zone.get("name") or zone_id or "Trust zone")
            current_stage = str(zone.get("authority_stage") or "observe").strip()
            promotion_rules = dict(zone.get("promotion_rules") or {})
            targets = [
                str(item).strip()
                for item in list(promotion_rules.get("eligible_next_stages", []) or [])
                if str(item).strip()
            ]
            if not targets:
                stages = sorted(self.list_authority_stages(), key=lambda item: int(item.get("sequence") or 0))
                active = [item for item in stages if str(item.get("stage_id") or "").strip().lower() != "suspended"]
                current_index = next((index for index, item in enumerate(active) if str(item.get("stage_id") or "") == current_stage), -1)
                if current_index >= 0 and current_index + 1 < len(active):
                    targets = [str(active[current_index + 1].get("stage_id") or current_stage)]
            if zone_id and targets:
                _append_recommendation(
                    subject_kind="trust_zone",
                    subject_id=zone_id,
                    target_stage=targets[0],
                    actor="system-steward",
                    basis="auto-promotion-recommendation",
                    title=title,
                )

        for arena in self.list_resource_arenas():
            if not isinstance(arena, dict):
                continue
            arena_id = str(arena.get("arena_id") or "").strip()
            target_stage = str((arena.get("promotion_eligibility") or {}).get("target_stage") or "").strip()
            if arena_id and target_stage:
                _append_recommendation(
                    subject_kind="resource_arena",
                    subject_id=arena_id,
                    target_stage=target_stage,
                    actor="system-steward",
                    basis="auto-arena-promotion-recommendation",
                    title=str(arena.get("name") or arena_id or "Resource arena"),
                )

        for contract in self.list_agent_supervision_contracts():
            if not isinstance(contract, dict):
                continue
            agent_id = str(contract.get("agent_id") or "").strip()
            current_stage = str(contract.get("authority_stage") or "observe").strip()
            if not agent_id:
                continue
            if current_stage == "observe":
                target_stage = "draft"
            elif current_stage == "draft":
                target_stage = "stage_alert"
            elif current_stage == "stage_alert":
                target_stage = "sandbox_live"
            elif current_stage == "sandbox_live":
                target_stage = "mature_live"
            else:
                continue
            _append_recommendation(
                subject_kind="agent",
                subject_id=agent_id,
                target_stage=target_stage,
                actor="system-steward",
                basis="auto-agent-promotion-recommendation",
                title=str(contract.get("label") or agent_id or "Agent"),
            )

        decision_rank = {"pending_consent": 0, "promote": 1, "suspend": 2, "hold": 3}
        recommendations.sort(
            key=lambda item: (
                decision_rank.get(str(item.get("decision") or ""), 9),
                -int(dict(item.get("metrics") or {}).get("total_reviews", 0) or 0),
                -float(dict(item.get("metrics") or {}).get("success_rate", 0.0) or 0.0),
                str(item.get("title") or ""),
            )
        )
        return recommendations[: max(1, int(limit))]

    def evaluate_promotion_claim(
        self,
        *,
        subject_kind: str,
        subject_id: str,
        target_stage: str = "",
        actor: str = "system",
        basis: str = "promotion-evaluation",
        human_consent: bool = False,
    ) -> dict[str, object]:
        kind = str(subject_kind or "").strip().lower()
        subject_key = str(subject_id or "").strip()
        if not kind or not subject_key:
            raise ValueError("subject_kind and subject_id are required")

        trust_zone = ""
        arena_id = ""
        current_stage = "observe"
        resolved_target_stage = str(target_stage or "").strip()

        if kind == "trust_zone":
            zone = self.trust_support.get_trust_zone(subject_key)
            if zone is None:
                raise KeyError(f"Unknown trust zone: {subject_key}")
            trust_zone = str(zone.get("zone_id") or subject_key)
            current_stage = str(zone.get("authority_stage") or "observe")
            if not resolved_target_stage:
                stages = sorted(self.trust_support.list_authority_stages(), key=lambda item: int(item.get("sequence") or 0))
                active = [item for item in stages if str(item.get("stage_id") or "").strip().lower() != "suspended"]
                current_index = next((index for index, item in enumerate(active) if str(item.get("stage_id") or "") == current_stage), 0)
                next_index = min(current_index + 1, max(len(active) - 1, 0))
                resolved_target_stage = str((active[next_index] if active else {}).get("stage_id") or current_stage)
        elif kind == "resource_arena":
            arena = self.trust_support.get_resource_arena(subject_key)
            if arena is None:
                raise KeyError(f"Unknown resource arena: {subject_key}")
            arena_id = str(arena.get("arena_id") or subject_key)
            trust_zone = str(arena.get("linked_zone_id") or "")
            zone = self.trust_support.get_trust_zone(trust_zone) if trust_zone else None
            current_stage = str((zone or {}).get("authority_stage") or "observe")
            if not resolved_target_stage:
                resolved_target_stage = str((arena.get("promotion_eligibility") or {}).get("target_stage") or current_stage)
        elif kind == "agent":
            contract = self.supervision_support.get_contract(subject_key)
            if contract is None:
                raise KeyError(f"Unknown supervised agent: {subject_key}")
            trust_zone = str(contract.get("trust_zone_id") or "")
            current_stage = str(contract.get("authority_stage") or "observe")
            if not resolved_target_stage:
                resolved_target_stage = "mature_live" if current_stage == "sandbox_live" else "sandbox_live"
        else:
            raise ValueError(f"Unsupported subject_kind: {subject_kind}")

        stage = self.trust_support.get_authority_stage(resolved_target_stage)
        if stage is None:
            raise KeyError(f"Unknown authority stage: {resolved_target_stage}")

        evidence = self.supervision_support.promotion_evidence(subject_kind=kind, subject_id=subject_key)
        engine = PromotionEngine()
        claim = engine.new_claim(
            subject_kind=kind,
            subject_id=subject_key,
            current_stage=current_stage,
            target_stage=resolved_target_stage,
            actor=actor,
            basis=basis,
            trust_zone=trust_zone,
            arena_id=arena_id,
            human_consent=human_consent,
            evidence_summary=dict(evidence.get("summary") or {}),
        )
        verdict = engine.evaluate_claim(
            claim,
            list(evidence.get("reviews") or []),
            threshold=engine.threshold_from_stage(stage),
        )
        payload = engine.to_dict(verdict)
        payload["claim"] = {
            "claim_id": claim.claim_id,
            "subject_kind": claim.subject_kind,
            "subject_id": claim.subject_id,
            "current_stage": claim.current_stage,
            "target_stage": claim.target_stage,
            "actor": claim.actor,
            "basis": claim.basis,
            "trust_zone": claim.trust_zone,
            "arena_id": claim.arena_id,
            "human_consent": claim.human_consent,
            "submitted_at": claim.submitted_at,
            "evidence_summary": dict(claim.evidence_summary),
        }
        payload["evidence"] = evidence
        self._append_promotion_record(
            event_type="promotion_evaluation",
            subject_kind=kind,
            subject_id=subject_key,
            status=str(payload.get("decision") or "hold"),
            actor=actor,
            basis=basis,
            trust_zone=trust_zone,
            arena_id=arena_id,
            authority_stage=resolved_target_stage,
            evidence={
                "current_stage": current_stage,
                "target_stage": resolved_target_stage,
                "metrics": dict(payload.get("metrics") or {}),
                "human_consent_required": bool(payload.get("human_consent_required")),
                "human_consent_present": bool(payload.get("human_consent_present")),
            },
        )
        return payload

    def apply_promotion_decision(
        self,
        *,
        subject_kind: str,
        subject_id: str,
        target_stage: str = "",
        actor: str = "system-steward",
        basis: str = "promotion-application",
        human_consent: bool = False,
    ) -> dict[str, object]:
        verdict = self.evaluate_promotion_claim(
            subject_kind=subject_kind,
            subject_id=subject_id,
            target_stage=target_stage,
            actor=actor,
            basis=basis,
            human_consent=human_consent,
        )
        kind = str(subject_kind or "").strip().lower()
        subject_key = str(subject_id or "").strip()
        decision = str(verdict.get("decision") or "hold").strip().lower()
        resolved_target_stage = str(verdict.get("target_stage") or target_stage or "").strip()
        current_stage = str(verdict.get("current_stage") or "observe").strip()

        if decision == "hold":
            return {
                "applied": False,
                "decision": decision,
                "reason": str(verdict.get("reason") or ""),
                "subject_kind": kind,
                "subject_id": subject_key,
                "target_stage": resolved_target_stage,
                "verdict": verdict,
            }
        if decision == "pending_consent" and not human_consent:
            raise PermissionError(str(verdict.get("reason") or "Explicit human consent is required before applying this promotion."))

        now = datetime.now(timezone.utc).isoformat()
        event_type = "promotion"
        action = "promote"
        updated: dict[str, object] | None = None

        if decision in {"promote", "pending_consent"}:
            if kind == "trust_zone":
                updated = self.promote_trust_zone(subject_key, actor=actor, basis=basis)
            elif kind == "agent":
                contract = self.supervision_support.get_contract(subject_key)
                if contract is None:
                    raise KeyError(f"Unknown supervised agent: {subject_key}")
                updated = self.supervision_support.update_contract(
                    subject_key,
                    {
                        "authority_stage": resolved_target_stage,
                        "status": "active",
                        "updated_at": now,
                    },
                )
                if updated is None:
                    raise KeyError(f"Unknown supervised agent: {subject_key}")
                self._append_promotion_record(
                    event_type="promotion",
                    subject_kind="agent",
                    subject_id=subject_key,
                    status=str(updated.get("status") or "active"),
                    actor=actor,
                    basis=basis,
                    trust_zone=str(updated.get("trust_zone_id") or verdict.get("trust_zone") or ""),
                    authority_stage=str(updated.get("authority_stage") or resolved_target_stage),
                    evidence={
                        "previous_stage": current_stage,
                        "target_stage": resolved_target_stage,
                        "human_consent_present": bool(human_consent),
                    },
                )
            elif kind == "resource_arena":
                return {
                    "applied": False,
                    "decision": decision,
                    "reason": "Resource arena promotion is not yet directly actionable because arenas do not persist an independent authority stage.",
                    "subject_kind": kind,
                    "subject_id": subject_key,
                    "target_stage": resolved_target_stage,
                    "verdict": verdict,
                }
        elif decision == "suspend":
            event_type = "suspension"
            action = "suspend"
            if kind == "trust_zone":
                action = "demote"
                event_type = "demotion"
                updated = self.demote_trust_zone(subject_key, actor=actor, reason=basis)
            elif kind == "agent":
                contract = self.supervision_support.get_contract(subject_key)
                if contract is None:
                    raise KeyError(f"Unknown supervised agent: {subject_key}")
                updated = self.supervision_support.update_contract(
                    subject_key,
                    {
                        "status": "suspended",
                        "updated_at": now,
                    },
                )
                if updated is None:
                    raise KeyError(f"Unknown supervised agent: {subject_key}")
                self._append_promotion_record(
                    event_type="suspension",
                    subject_kind="agent",
                    subject_id=subject_key,
                    status=str(updated.get("status") or "suspended"),
                    actor=actor,
                    basis=basis,
                    trust_zone=str(updated.get("trust_zone_id") or verdict.get("trust_zone") or ""),
                    authority_stage=str(updated.get("authority_stage") or current_stage),
                    evidence={
                        "previous_stage": current_stage,
                        "target_stage": resolved_target_stage,
                        "decision": decision,
                    },
                )
            elif kind == "resource_arena":
                updated = self.suspend_resource_arena(subject_key, actor=actor, reason=basis)
        else:
            raise ValueError(f"Unsupported promotion decision: {decision}")

        return {
            "applied": True,
            "action": action,
            "decision": "promote" if decision == "pending_consent" else decision,
            "event_type": event_type,
            "subject_kind": kind,
            "subject_id": subject_key,
            "target_stage": resolved_target_stage,
            "updated": dict(updated or {}),
            "verdict": verdict,
        }

    def apply_promotion_recommendations(
        self,
        *,
        actor: str = "system-steward",
        basis: str = "auto-apply-promotion-recommendations",
        limit: int = 12,
    ) -> dict[str, object]:
        recommendations = self.list_promotion_recommendations(limit=limit)
        applied: list[dict[str, object]] = []
        skipped: list[dict[str, object]] = []
        failed: list[dict[str, object]] = []

        for item in recommendations:
            decision = str(item.get("decision") or "").strip().lower()
            subject_kind = str(item.get("subject_kind") or "").strip()
            subject_id = str(item.get("subject_id") or "").strip()
            target_stage = str(item.get("target_stage") or "").strip()
            if decision not in {"promote", "suspend"}:
                skipped.append(
                    {
                        "subject_kind": subject_kind,
                        "subject_id": subject_id,
                        "decision": decision,
                        "reason": str(item.get("reason") or "Recommendation requires review before application."),
                    }
                )
                continue
            try:
                result = self.apply_promotion_decision(
                    subject_kind=subject_kind,
                    subject_id=subject_id,
                    target_stage=target_stage,
                    actor=actor,
                    basis=basis,
                    human_consent=False,
                )
            except (KeyError, PermissionError, ValueError) as exc:
                failed.append(
                    {
                        "subject_kind": subject_kind,
                        "subject_id": subject_id,
                        "decision": decision,
                        "error": str(exc),
                    }
                )
                continue
            if bool(result.get("applied")):
                applied.append(result)
            else:
                skipped.append(
                    {
                        "subject_kind": subject_kind,
                        "subject_id": subject_id,
                        "decision": decision,
                        "reason": str(result.get("reason") or "Recommendation was not applied."),
                    }
                )

        return {
            "status": "ok",
            "recommendation_count": len(recommendations),
            "applied_count": len(applied),
            "skipped_count": len(skipped),
            "failed_count": len(failed),
            "applied": applied,
            "skipped": skipped,
            "failed": failed,
        }

    def promote_trust_zone(self, zone_id: str, *, actor: str = "Chris", basis: str = "manual-promotion") -> dict:
        zone = self.trust_support.get_trust_zone(zone_id)
        if zone is None:
            raise KeyError(f"Unknown trust zone: {zone_id}")

        stages = sorted(self.trust_support.list_authority_stages(), key=lambda item: int(item.get("sequence") or 0))
        active_stages = [item for item in stages if isinstance(item, dict) and str(item.get("stage_id") or "").strip().lower() != "suspended"]
        current_stage_id = str(zone.get("authority_stage") or "observe")
        current_index = next((index for index, item in enumerate(active_stages) if str(item.get("stage_id") or "") == current_stage_id), 0)
        target_index = min(current_index + 1, max(len(active_stages) - 1, 0))
        target_stage = active_stages[target_index] if active_stages else {"stage_id": current_stage_id, "approval_requirements": {}}
        target_stage_id = str(target_stage.get("stage_id") or current_stage_id)
        requirements = target_stage.get("approval_requirements") if isinstance(target_stage.get("approval_requirements"), dict) else {}
        updated = self.trust_support.update_trust_zone(
            zone_id,
            {
                "authority_stage": target_stage_id,
                "approval_mode": str(requirements.get("pre_action") or zone.get("approval_mode") or ""),
                "updated_at": datetime.now(timezone.utc).isoformat(),
            },
        )
        if updated is None:
            raise KeyError(f"Unknown trust zone: {zone_id}")
        self._append_promotion_record(
            event_type="promotion",
            subject_kind="trust_zone",
            subject_id=zone_id,
            status=str(updated.get("status") or "active"),
            actor=actor,
            basis=basis,
            trust_zone=zone_id,
            authority_stage=target_stage_id,
            evidence={
                "previous_stage": current_stage_id,
                "approval_mode": str(updated.get("approval_mode") or ""),
            },
        )
        return updated

    def demote_trust_zone(self, zone_id: str, *, actor: str = "Chris", reason: str = "manual-demotion") -> dict:
        zone = self.trust_support.get_trust_zone(zone_id)
        if zone is None:
            raise KeyError(f"Unknown trust zone: {zone_id}")

        stages = sorted(self.trust_support.list_authority_stages(), key=lambda item: int(item.get("sequence") or 0))
        active_stages = [item for item in stages if isinstance(item, dict) and str(item.get("stage_id") or "").strip().lower() != "suspended"]
        demotion_rules = zone.get("demotion_rules") if isinstance(zone.get("demotion_rules"), dict) else {}
        fallback_stage_id = str(demotion_rules.get("fallback_stage") or "").strip()
        current_stage_id = str(zone.get("authority_stage") or "observe")
        if fallback_stage_id:
            target_stage = self.trust_support.get_authority_stage(fallback_stage_id) or {}
        else:
            current_index = next((index for index, item in enumerate(active_stages) if str(item.get("stage_id") or "") == current_stage_id), 0)
            target_index = max(current_index - 1, 0)
            target_stage = active_stages[target_index] if active_stages else {}
        target_stage_id = str(target_stage.get("stage_id") or current_stage_id)
        requirements = target_stage.get("approval_requirements") if isinstance(target_stage.get("approval_requirements"), dict) else {}
        updated = self.trust_support.update_trust_zone(
            zone_id,
            {
                "authority_stage": target_stage_id,
                "approval_mode": str(requirements.get("pre_action") or zone.get("approval_mode") or ""),
                "updated_at": datetime.now(timezone.utc).isoformat(),
            },
        )
        if updated is None:
            raise KeyError(f"Unknown trust zone: {zone_id}")
        self._append_promotion_record(
            event_type="demotion",
            subject_kind="trust_zone",
            subject_id=zone_id,
            status=str(updated.get("status") or "active"),
            actor=actor,
            basis=reason,
            trust_zone=zone_id,
            authority_stage=target_stage_id,
            evidence={
                "previous_stage": current_stage_id,
                "approval_mode": str(updated.get("approval_mode") or ""),
            },
        )
        return updated

    def suspend_resource_arena(self, arena_id: str, *, actor: str = "Chris", reason: str = "manual-suspension") -> dict:
        arena = self.trust_support.get_resource_arena(arena_id)
        if arena is None:
            raise KeyError(f"Unknown resource arena: {arena_id}")
        updated = self.trust_support.update_resource_arena(
            arena_id,
            {
                "status": "suspended",
                "updated_at": datetime.now(timezone.utc).isoformat(),
            },
        )
        if updated is None:
            raise KeyError(f"Unknown resource arena: {arena_id}")
        self._append_promotion_record(
            event_type="suspension",
            subject_kind="resource_arena",
            subject_id=arena_id,
            status="suspended",
            actor=actor,
            basis=reason,
            trust_zone=str(updated.get("linked_zone_id") or ""),
            arena_id=arena_id,
            authority_stage="suspended",
            evidence={"previous_status": str(arena.get("status") or "")},
        )
        return updated

    def resume_resource_arena(self, arena_id: str, *, actor: str = "Chris", reason: str = "manual-resume") -> dict:
        arena = self.trust_support.get_resource_arena(arena_id)
        if arena is None:
            raise KeyError(f"Unknown resource arena: {arena_id}")
        updated = self.trust_support.update_resource_arena(
            arena_id,
            {
                "status": "active",
                "updated_at": datetime.now(timezone.utc).isoformat(),
            },
        )
        if updated is None:
            raise KeyError(f"Unknown resource arena: {arena_id}")
        self._append_promotion_record(
            event_type="resumption",
            subject_kind="resource_arena",
            subject_id=arena_id,
            status="active",
            actor=actor,
            basis=reason,
            trust_zone=str(updated.get("linked_zone_id") or ""),
            arena_id=arena_id,
            authority_stage=str((updated.get("promotion_eligibility") or {}).get("target_stage") or "registry"),
            evidence={"previous_status": str(arena.get("status") or "")},
        )
        return updated

    def assess_action_boundary(
        self,
        *,
        zone_id: str,
        arena_id: str = "",
        action_type: str,
        requested_stage: str = "sandbox_live",
    ) -> dict[str, object]:
        # G3: Cap the requested stage at the active household mode's autonomy_ceiling.
        # This is applied BEFORE trust-zone logic so the mode ceiling is unconditional.
        effective_stage = requested_stage
        mode_ceiling_applied = False
        active_mode_id = "normal"
        try:
            from .mode_resolver import get_active_mode_contract, STAGE_SEQUENCE
            active_contract = get_active_mode_contract()
            active_mode_id = active_contract.mode_id
            ceiling = active_contract.autonomy_ceiling
            ceiling_seq = STAGE_SEQUENCE.get(ceiling, 99)
            requested_seq = STAGE_SEQUENCE.get(requested_stage, 0)
            if requested_seq > ceiling_seq:
                effective_stage = ceiling
                mode_ceiling_applied = True
                if effective_stage in {"monitor", "suggest"}:
                    # Stages below sandbox → deny immediately; JARVIS must not act autonomously.
                    return {
                        "decision": "deny",
                        "reason": (
                            f"Active household mode '{active_mode_id}' caps autonomy at "
                            f"'{ceiling}'. Requested stage '{requested_stage}' is not permitted."
                        ),
                        "trust_zone": zone_id,
                        "authority_stage": effective_stage,
                        "approval_mode": "deny",
                        "arena_status": "mode_ceiling_applied",
                        "action_type": action_type,
                        "mode_ceiling": ceiling,
                        "active_mode": active_mode_id,
                    }
        except Exception:
            pass  # fail open — let existing trust-zone logic decide

        zone = self.trust_support.get_trust_zone(zone_id)
        if zone is None:
            return {
                "decision": "deny",
                "reason": f"Unknown trust zone '{zone_id}'.",
                "trust_zone": zone_id,
                "authority_stage": "unknown",
                "approval_mode": "deny",
                "arena_status": "unknown",
            }

        arena = self.trust_support.get_resource_arena(arena_id) if arena_id else None
        arena_status = str(arena.get("status") or "") if isinstance(arena, dict) else ""
        if arena_id and arena is None:
            return {
                "decision": "deny",
                "reason": f"Unknown resource arena '{arena_id}'.",
                "trust_zone": zone_id,
                "authority_stage": str(zone.get("authority_stage") or "unknown"),
                "approval_mode": str(zone.get("approval_mode") or ""),
                "arena_status": "unknown",
            }

        zone_status = str(zone.get("status") or "unknown").strip().lower()
        if zone_status != "active":
            return {
                "decision": "deny",
                "reason": f"Trust zone '{zone_id}' is not active.",
                "trust_zone": zone_id,
                "authority_stage": str(zone.get("authority_stage") or "unknown"),
                "approval_mode": str(zone.get("approval_mode") or ""),
                "arena_status": arena_status or "unknown",
            }

        if arena_status.strip().lower() in {"suspended", "paused"}:
            return {
                "decision": "deny",
                "reason": f"Resource arena '{arena_id}' is {arena_status}.",
                "trust_zone": zone_id,
                "authority_stage": str(zone.get("authority_stage") or "unknown"),
                "approval_mode": str(zone.get("approval_mode") or ""),
                "arena_status": arena_status,
            }

        stages = [item for item in self.trust_support.list_authority_stages() if isinstance(item, dict)]
        stage_lookup = {str(item.get("stage_id") or ""): item for item in stages}
        current_stage_id = str(zone.get("authority_stage") or "observe")
        current_stage = stage_lookup.get(current_stage_id, {})
        # G3: use effective_stage (mode-capped) instead of raw requested_stage
        _lookup_stage = effective_stage if mode_ceiling_applied else requested_stage
        requested_stage_id = _lookup_stage if _lookup_stage in stage_lookup else {
            "live": "mature_live",
            "staged": "stage_alert",
            "draft": "draft",
        }.get(_lookup_stage, _lookup_stage)
        requested = stage_lookup.get(requested_stage_id, {})
        current_sequence = int(current_stage.get("sequence") or 0)
        requested_sequence = int(requested.get("sequence") or current_sequence)

        # Consult canonical action taxonomy for two critical checks:
        # 1. Unknown actions fail CLOSED (B3 — fail-closed behavior)
        # 2. Hard boundary denials block regardless of zone stage (B7 — policy rails)
        from .policy_rails import get_action_policy
        policy = get_action_policy(action_type)

        # Unknown action type → deny (fail closed — B3)
        if policy.action_type == "_unknown":
            return {
                "decision": "deny",
                "reason": (
                    f"Unknown action type '{action_type}' is not registered in the canonical "
                    "action taxonomy. Unknown actions fail closed. Register it in "
                    "jarvis/policy_rails.py to enable it."
                ),
                "trust_zone": zone_id,
                "authority_stage": current_stage_id,
                "approval_mode": "deny",
                "arena_status": arena_status or "active",
                "action_type": action_type,
                "registered": False,
            }

        # Hard boundary deny (money, legal, identity, security, children, reputation, system — B7)
        # L9.1: constitutional citation is generated so the denial is traceable to a principle.
        if policy.hard_boundary and policy.approval_mode == "deny":
            citation_id: str | None = None
            principle_text: str = ""
            try:
                from .constitution_engine import ConstitutionEngine
                _ce = ConstitutionEngine()
                _family_principles = {
                    "financial": ["III.1.mandate_first", "II.4.financial_boundary"],
                    "legal": ["II.4.financial_boundary", "I.1.identity"],
                    "identity": ["I.1.identity"],
                    "security": ["I.1.identity", "III.3.legible_agency"],
                    "children": ["I.1.identity", "III.3.legible_agency"],
                    "publishing": ["III.3.legible_agency"],
                    "system": ["III.3.legible_agency"],
                }
                principle_ids = _family_principles.get(policy.family, ["III.3.legible_agency"])
                import uuid as _uuid
                cit = _ce.cite(
                    decision_id=str(_uuid.uuid4()),
                    actor="system",
                    recommendation_summary=(
                        f"Deny '{action_type}' — hard boundary family '{policy.family}' "
                        "requires explicit human initiation."
                    ),
                    principle_ids=principle_ids,
                    authority_stage=current_stage_id,
                    uncertainty_level="none",
                )
                citation_id = cit.decision_id
                p = _ce.get_principle(principle_ids[0])
                principle_text = p.get("text", "")
            except Exception:
                pass  # citation failure never blocks the deny
            result = {
                "decision": "deny",
                "reason": (
                    f"Action '{action_type}' is in hard boundary family '{policy.family}'. "
                    "Requires explicit human initiation — no automated agent may execute it."
                ),
                "trust_zone": zone_id,
                "authority_stage": current_stage_id,
                "approval_mode": "deny",
                "arena_status": arena_status or "active",
                "action_type": action_type,
                "family": policy.family,
                "risk_tier": policy.risk_tier,
                "hard_boundary": True,
                "registered": True,
            }
            if citation_id:
                result["constitution_citation_id"] = citation_id
                result["principle_basis"] = principle_text
            return result

        # Stage if zone stage below required minimum (original sequence logic — B1)
        if action_type in {
            "home_control", "calendar_route", "signal_resolution",
            "notification_workflow", "reminder_workflow", "publishing_review",
            "focus_workflow", "huddle_workflow", "stewardship_lane_review",
            "foundry_proposal_review",
        } and current_sequence < requested_sequence:
            return {
                "decision": "stage",
                "reason": f"{zone_id} is at {current_stage_id} and must promote before live {action_type} actions.",
                "trust_zone": zone_id,
                "authority_stage": current_stage_id,
                "approval_mode": str(zone.get("approval_mode") or ""),
                "arena_status": arena_status or "active",
                "action_type": action_type,
                "family": policy.family,
                "risk_tier": policy.risk_tier,
                "registered": True,
            }

        return {
            "decision": "allow",
            "reason": f"{zone_id} is cleared for {action_type}.",
            "trust_zone": zone_id,
            "authority_stage": current_stage_id,
            "approval_mode": str(zone.get("approval_mode") or ""),
            "arena_status": arena_status or "active",
            "action_type": action_type,
            "family": policy.family,
            "risk_tier": policy.risk_tier,
            "registered": True,
        }

