    def vendor_prep(
        self,
        actor_name: str,
        part_name: str,
        vendor_target: str,
        process: str,
        material: str,
        notes: str,
    ) -> dict:
        actor = self.get_actor(actor_name)
        prep = self.workshop_support.prepare_vendor_prep(
            actor.display_name,
            part_name,
            vendor_target,
            process,
            material,
            notes,
        )
        task_lane = self._task_lane_for_domain("workshop")
        threshold = self._approval_threshold_for_domain("workshop")
        lifecycle = self.catalyst_support.transition_work_item(
            actor=actor.display_name,
            title=f"Vendor package for {part_name}",
            domain="workshop",
            lane=str(task_lane.get("lane", "")).strip() or "fabrication-and-vendors",
            owner_agent=str(task_lane.get("owner_agent", "")).strip() or "Rocket",
            stage=WorkLifecycleStage.STAGED_ACTION,
            status="pending-approval",
            artifact_type="vendor-prep",
            source="workshop-vendor-prep",
            review_level=str(threshold.get("level", "review-before-external")).strip() or "review-before-external",
            rationale="External vendor work must be staged before any external commitment.",
            record_id=str(prep.get("prep_id", "")).strip(),
            metadata={"vendor_target": vendor_target, "process": process, "material": material},
        )
        approval_request = ApprovalRequest(
            request_id=str(uuid.uuid4()),
            actor=actor.display_name,
            room="workshop",
            request=f"Approve vendor package for {part_name} to {vendor_target}",
            action_class="EXECUTE_MEDIUM_RISK",
            second_factor_required=False,
            status="pending",
            rationale="External vendor submission requires explicit approval before any quote request is sent.",
            domain="workshop",
            lane=str(task_lane.get("lane", "")).strip(),
            owner_agent=str(task_lane.get("owner_agent", "")).strip(),
            lifecycle_work_id=str(lifecycle.get("work_id", "")).strip(),
        )
        self.approval_store.add(approval_request)
        prep["approval_request_id"] = approval_request.request_id
        prep["status"] = "pending-approval"
        prep["work_id"] = str(lifecycle.get("work_id", "")).strip()
        return self.workshop_support.save_vendor_prep(prep)

    def list_vendor_preps(self, limit: int = 10) -> list[dict]:
        return self.workshop_support.list_vendor_preps(limit=limit)

    def update_vendor_prep_status(self, prep_id: str, status: str) -> dict | None:
        updated = self.workshop_support.update_vendor_prep_status(prep_id, status)
        if updated is None:
            return None
        work_id = str(updated.get("work_id", "")).strip()
        normalized = str(status).strip().lower()
        if work_id:
            if normalized in {"staged", "pending-approval"}:
                self.catalyst_support.transition_work_item(
                    actor=str(updated.get("actor", "Chris")).strip() or "Chris",
                    title=f"Vendor package for {str(updated.get('part_name', 'part')).strip() or 'part'}",
                    domain="workshop",
                    lane="fabrication-and-vendors",
                    owner_agent="Rocket",
                    stage=WorkLifecycleStage.STAGED_ACTION,
                    status=normalized,
                    artifact_type="vendor-prep",
                    source="workshop-update-vendor-prep",
                    review_level="review-before-external",
                    rationale="The vendor prep artifact changed state.",
                    work_id=work_id,
                    record_id=str(updated.get("prep_id", "")).strip(),
                )
            elif normalized in {"completed", "sent"}:
                self._mark_work_item_outcome(str(updated.get("actor", "Chris")).strip() or "Chris", {"work_id": work_id, "title": f"Vendor prep {prep_id}", "domain": "workshop", "lane": "fabrication-and-vendors", "owner_agent": "Rocket"}, status="succeeded", rationale="The vendor prep completed successfully.", artifact_type="vendor-prep")
            elif normalized in {"archived", "cancelled"}:
                self._mark_work_item_outcome(str(updated.get("actor", "Chris")).strip() or "Chris", {"work_id": work_id, "title": f"Vendor prep {prep_id}", "domain": "workshop", "lane": "fabrication-and-vendors", "owner_agent": "Rocket"}, status="abandoned", rationale="The vendor prep was archived instead of executed.", artifact_type="vendor-prep")
        self._invalidate_snapshot_cache(surfaces=("pipeline_review", "pipeline_state", "dashboard", "shell_state", "proactive_state"))
        return updated

    def _vendor_prep_sandbox_job_id(self, prep_id: str) -> str:
        return f"vendor-prep:{str(prep_id).strip()}"

    def _calendar_route_sandbox_queue_path(self) -> Path:
        return self._repo_root() / "data" / "state" / "calendar_route_sandbox_jobs.json"

    def _load_calendar_route_sandbox_store(self) -> dict[str, Any]:
        path = self._calendar_route_sandbox_queue_path()
        if not path.exists():
            return {"jobs": []}
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            return {"jobs": []}
        jobs = payload.get("jobs") if isinstance(payload, dict) else []
        if not isinstance(jobs, list):
            jobs = []
        return {"jobs": [dict(item) for item in jobs if isinstance(item, dict)]}

    def _save_calendar_route_sandbox_store(self, payload: dict[str, Any]) -> None:
        path = self._calendar_route_sandbox_queue_path()
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(payload, indent=2) + "\n", encoding="utf-8")

    def _calendar_route_sandbox_job_id(self, event_id: str) -> str:
        return f"calendar-route:{str(event_id).strip()}"

    def _calendar_route_sandbox_workspace(self, event_id: str) -> Path:
        slug = re.sub(r"[^a-z0-9]+", "-", str(event_id or "").strip().lower()).strip("-") or "route"
        return self._repo_root() / "data" / "state" / "calendar_route_sandbox" / slug

    def _calendar_route_sandbox_report_root(self) -> Path:
        root = self._repo_root() / "data" / "system" / "calendar_route_sandbox_reports"
        root.mkdir(parents=True, exist_ok=True)
        return root

    def _calendar_route_record(self, event_id: str) -> dict[str, Any] | None:
        for item in self._load_calendar_route_sandbox_store().get("jobs", []):
            if str(item.get("event_id", "")).strip() == str(event_id).strip():
                return dict(item)
        return None

    def _save_calendar_route_record(self, route_job: dict[str, Any]) -> dict[str, Any]:
        store = self._load_calendar_route_sandbox_store()
        event_id = str(route_job.get("event_id", "")).strip()
        if not event_id:
            raise ValueError("Calendar route event id is required")
        records = list(store.get("jobs", []))
        replaced = False
        for index, item in enumerate(records):
            if str(item.get("event_id", "")).strip() == event_id:
                records[index] = dict(route_job)
                replaced = True
                break
        if not replaced:
            records.append(dict(route_job))
        store["jobs"] = records
        self._save_calendar_route_sandbox_store(store)
        return dict(route_job)

    def calendar_route_sandbox_jobs(self, limit: int = 8) -> list[dict[str, Any]]:
        jobs: list[dict[str, Any]] = []
        eligible_statuses = {
            "staged-for-review",
            "sandbox-queued",
            "sandbox-running",
            "sandboxed",
            "sandbox-failed",
        }
        for item in self._load_calendar_route_sandbox_store().get("jobs", []):
            status = str(item.get("status", "")).strip()
            if status not in eligible_statuses:
                continue
            event_id = str(item.get("event_id", "")).strip()
            if not event_id:
                continue
            jobs.append(
                {
                    "job_id": self._calendar_route_sandbox_job_id(event_id),
                    "title": f"Calendar route for {str(item.get('title', '')).strip() or 'event'}",
                    "status": status,
                    "job_type": "calendar-route",
                    "target": str(item.get("location", "")).strip(),
                    "review_level": "sandbox-live",
                    "summary": str(item.get("sandbox_message", "")).strip() or str(item.get("location", "")).strip(),
                    "auto_allowed": True,
                    "updated_at": str(item.get("updated_at") or item.get("created_at") or ""),
                    "last_sandbox_run_id": str(item.get("sandbox_run_id") or ""),
                    "event_id": event_id,
                }
            )
            if len(jobs) >= max(1, int(limit)):
                break
        return jobs

